import { NextRequest, NextResponse } from 'next/server'
import { query } from '@/lib/db'

export const runtime = 'nodejs'

const SEED_SECRET = process.env.MIGRATE_SECRET ?? 'sparkie-migrate-2026'

type SkillDef = { name: string; category: string; description: string; content: string }

// Skill content is base64-encoded to avoid TypeScript string escaping issues
const SKILL_SEEDS: SkillDef[] = [
  { name: "email", category: "Email", description: "Email operations: search/read threads, compose/reply/forward, CC enforcement, style matching, unsubscribe, follow-up, draft edit flow, send confirmation rules", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "email-style-matching", category: "Email", description: "Email style matching quick reference \u2014 tone, language, signature, greeting patterns", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "email-examples", category: "Email", description: "Extended email examples \u2014 CC edge cases, unsubscribe flow, draft edit flow", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "calendar", category: "Calendar", description: "Calendar: scheduling, RSVP, conflict priority analysis, meeting title generation, all-day events, description field rules, examples", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "calendar-receiving-invitation", category: "Calendar", description: "Handling verbal and Google Calendar invitations \u2014 accept, decline, conflict resolution, auto-reschedule", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "calendar-sending-invitation", category: "Calendar", description: "Sending meeting invites \u2014 freebusy workflow, external attendees, multi-person scheduling", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "calendar-conflict-handling", category: "Calendar", description: "Full conflict handling \u2014 detection, classification, priority matrix, alternative time finding", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "calendar-meeting-title", category: "Calendar", description: "Meeting title generation templates and algorithm \u2014 interview, 1:1, customer, recurring, all-hands", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "calendar-examples", category: "Calendar", description: "Extended calendar examples \u2014 multi-person, cross-timezone, recurring reschedule, auto-reschedule after conflict", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "browser-use", category: "Automation", description: "Browser automation via Hyperbrowser \u2014 decision tree, profile vs session, cost guide, polling rules", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "a2ui-card-gen", category: "UI", description: "A2UI card generation \u2014 component reference, action item pattern, Sparkie purple theme rules", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "cta-card-gen", category: "UI", description: "CTA card extraction \u2014 collect/filter/rank/verify pipeline, verbatim URL rule", content: Buffer.from("", "base64").toString("utf-8") }
,
  { name: "social", category: "Social", description: "Social media posting — Twitter/Instagram/Reddit/TikTok/Discord, Mode A/B HITL, per-platform rules", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "music", category: "Creative", description: "Music generation — ACE Step 1.5 + MiniMax pipelines, lyrics, tags format, pipeline quirks", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "video", category: "Creative", description: "Video generation — 6 models: seedance/seedance-pro/wan/ltx-2/veo/grok-video", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "self-repair", category: "System", description: "Self-repair — read-before-write rule, deploy/rollback workflow, SWC error patterns", content: Buffer.from("", "base64").toString("utf-8") },
  { name: "about-sparkie", category: "Meta", description: "Self-knowledge doc — what Sparkie is, all capabilities, platform, identity", content: Buffer.from("", "base64").toString("utf-8") }
]

export async function POST(req: NextRequest) {
  const body = await req.json().catch(() => ({})) as { secret?: string }
  if (body.secret !== SEED_SECRET) {
    return NextResponse.json({ ok: false, error: 'Unauthorized' }, { status: 401 })
  }

  await query(`CREATE TABLE IF NOT EXISTS sparkie_skills (
    id SERIAL PRIMARY KEY,
    user_id TEXT,
    name TEXT NOT NULL,
    description TEXT DEFAULT '',
    source_url TEXT DEFAULT '',
    category TEXT DEFAULT 'Custom',
    content TEXT DEFAULT '',
    installed_at TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(name)
  )`).catch(() => {})

  const results: Array<{ name: string; status: string }> = []

  for (const skill of SKILL_SEEDS) {
    try {
      await query(
        `INSERT INTO sparkie_skills (user_id, name, description, source_url, category, content)
         VALUES ('global', $1, $2, $3, $4, $5)
         ON CONFLICT (name) DO UPDATE SET
           description = EXCLUDED.description,
           category = EXCLUDED.category,
           content = EXCLUDED.content,
           source_url = EXCLUDED.source_url,
           installed_at = NOW()`,
        [skill.name, skill.description, skill.name, skill.category, skill.content]
      )
      results.push({ name: skill.name, status: 'seeded' })
    } catch (e) {
      results.push({ name: skill.name, status: 'error: ' + String(e) })
    }
  }

  const succeeded = results.filter(r => r.status === 'seeded').length
  return NextResponse.json({
    ok: true,
    message: 'Seeded ' + succeeded + '/' + SKILL_SEEDS.length + ' skills into sparkie_skills',
    results
  })
}
